patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..2d852e7fabd0 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2229,6 +2229,26 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return BitOp;
     }

+    // For variable shift amount, if known less than bit width, we can simplify.
+    Value *ShAmt = II->getArgOperand(2);
+    KnownBits KnownShAmt = computeKnownBits(ShAmt, 0, II);
+    // If ShAmt is an Argument with a range attribute, incorporate that.
+    if (const Argument *Arg = dyn_cast<Argument>(ShAmt))
+      if (auto Range = Arg->getRange())
+        KnownShAmt = KnownShAmt.unionWith(Range->toKnownBits());
+    if (KnownShAmt.getMaxValue().ult(BitWidth)) {
+      // fshl(X, 0, ShAmt) --> shl X, ShAmt
+      // fshl(X, undef, ShAmt) --> shl X, ShAmt
+      if (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))
+        return BinaryOperator::CreateShl(Op0, ShAmt);
+      // fshl(0, X, ShAmt) --> lshr X, (BW - ShAmt)
+      // fshl(undef, X, ShAmt) --> lshr X, (BW - ShAmt)
+      if (match(Op0, m_ZeroInt()) || match(Op0, m_Undef())) {
+        Value *Sub = Builder.CreateSub(ConstantInt::get(Ty, BitWidth), ShAmt);
+        return BinaryOperator::CreateLShr(Op1, Sub);
+      }
+    }
+
     // Left or right might be masked.
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

